SELECT id, article_id, content, author, color, position, ip, created_at
FROM danmaku
WHERE article_id = #{articleId}
ORDER BY id ASC
LIMIT #{limit}

SELECT id, article_id, content, author, color, position, ip, created_at
FROM danmaku
WHERE article_id = #{articleId} AND id > #{afterId}
ORDER BY id ASC
LIMIT #{limit}
